import { useLocation, useNavigate } from "react-router-dom";
import "./styles/Books.css";

function LibrarianBooks() {
  const navigate = useNavigate();
  const location = useLocation();
  const genre = location.state?.genre || "Literature";

  // TEMP FRONTEND DATA (same structure as CategoryBooks)
  const booksByGenre = {
    Literature: [
      { title: "Hamlet", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477123-L.jpg" },
      { title: "Macbeth", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477109-L.jpg" },
      { title: "Pride and Prejudice", author: "Jane Austen", cover: "https://covers.openlibrary.org/b/isbn/9780141439518-L.jpg" }
    ],
    Fantasy: [
      { title: "Harry Potter", author: "J K Rowling", cover: "https://covers.openlibrary.org/b/isbn/9780439554930-L.jpg" },
      { title: "The Hobbit", author: "Tolkien", cover: "https://covers.openlibrary.org/b/isbn/9780345339683-L.jpg" }
    ]
  };

  const books = booksByGenre[genre] || [];

  return (
    <div className="books-page">
      <h1 className="books-title">{genre} Books</h1>

      <div className="books-grid">
        {books.map((book, i) => (
          <div key={i} className="book-card">
            <img src={book.cover} alt={book.title} />
            <h3>{book.title}</h3>
            <p>{book.author}</p>

            {/* librarian hint */}
            <span className="card-status avail">Managed by Librarian</span>
          </div>
        ))}
      </div>

      <button className="back-btn" onClick={() => navigate(-1)}>
        ← Back to Librarian Panel
      </button>
    </div>
  );
}

export default LibrarianBooks;
